import{_ as o,c as e,o as t,aR as a}from"./chunks/framework.MDQz7FCs.js";const b=JSON.parse('{"title":"About","description":"","frontmatter":{"title":"About","editLink":true},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1778480909000}'),r={name:"about.md"},i=a('<h1 id="about-qrcode-with-logos" tabindex="-1">About qrcode-with-logos <a class="header-anchor" href="#about-qrcode-with-logos" aria-label="Permalink to &quot;About qrcode-with-logos&quot;">​</a></h1><h2 id="what-is-qrcode-with-logos" tabindex="-1">What is qrcode-with-logos? <a class="header-anchor" href="#what-is-qrcode-with-logos" aria-label="Permalink to &quot;What is qrcode-with-logos?&quot;">​</a></h2><p>qrcode-with-logos is a powerful and easy-to-use JavaScript library that allows you to generate beautiful QR codes with custom logos and extensive styling options. Built on top of the popular <code>qrcode</code> library, it extends functionality with additional customization features that make your QR codes stand out.</p><h2 id="our-mission" tabindex="-1">Our Mission <a class="header-anchor" href="#our-mission" aria-label="Permalink to &quot;Our Mission&quot;">​</a></h2><p>We aim to provide developers with a simple yet flexible tool to create visually appealing QR codes that can incorporate brand identities through logos, custom colors, and various styling options. Whether you&#39;re building a website, mobile app, or marketing campaign, qrcode-with-logos helps you create QR codes that match your design aesthetic.</p><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><p>qrcode-with-logos was created in 2019 by <a href="https://github.com/zxpsuper" target="_blank" rel="noreferrer">zxpsuper</a> as a side project to solve the need for customizable QR codes with logos. Since then, it has grown into a widely used library with thousands of downloads per month on npm.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>Logo Integration</strong>: Easily add logos to your QR codes</li><li><strong>Customizable Dots</strong>: Multiple dot styles and color options</li><li><strong>Corner Styling</strong>: Different corner types and colors</li><li><strong>Color Customization</strong>: Full control over colors</li><li><strong>Download Support</strong>: Built-in methods to download QR codes</li><li><strong>Browser-based</strong>: Uses Canvas API for high-quality rendering</li></ul><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><ul><li><strong>JavaScript</strong>: Core language</li><li><strong>Canvas API</strong>: For QR code rendering</li><li><strong>qrcode</strong>: Base dependency for QR code generation</li></ul><h2 id="open-source" tabindex="-1">Open Source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open Source&quot;">​</a></h2><p>qrcode-with-logos is open source software released under the MIT License. We welcome contributions from the community! If you&#39;d like to contribute, please visit our <a href="https://github.com/zxpsuper/qrcode-with-logos" target="_blank" rel="noreferrer">GitHub repository</a>.</p><h2 id="acknowledgments" tabindex="-1">Acknowledgments <a class="header-anchor" href="#acknowledgments" aria-label="Permalink to &quot;Acknowledgments&quot;">​</a></h2><p>Special thanks to:</p><ul><li>The <a href="https://github.com/soldair/node-qrcode" target="_blank" rel="noreferrer">qrcode</a> library for providing the foundation</li><li>All our contributors and users for their support and feedback</li></ul>',16),s=[i];function n(l,d,c,h,u,p){return t(),e("div",null,s)}const m=o(r,[["render",n]]);export{b as __pageData,m as default};
